def go_to(page_name: str):
    st.session_state.page = page_name


# ------------------------------------------------------------------
# Live progress diagram (lights up as the user moves through the flow)
# ------------------------------------------------------------------
PROGRESS_STEPS = [
    ("1", "Choose mode", "Speed or Depth research"),
    ("2", "Enter API keys", "Groq / Mistral + Tavily"),
    ("3", "Write your question", "The topic to research"),
    ("4", "Run research", "Supervisor loop searches & drafts"),
    ("5", "Final report", "Polished, cited answer"),
]


def compute_progress_state(keys_ok: bool, query_ok: bool) -> tuple:
    """
    Returns (active_index, status_override) where active_index is the step
    (1-5) currently in focus, and status_override is None / "running" / "error".
    Step 1 (mode) is always considered done since it always has a default value.
    """
    if st.session_state.running:
        return 4, "running"

    if st.session_state.has_run:
        if st.session_state.run_error:
            return 4, "error"
        result = st.session_state.result
        if result and result.get("final_report"):
            return 6, None  # past the last step -> everything shown as done
        return 4, None  # finished but no final report (e.g. clarification)

    if query_ok:
        return 4, None
    if keys_ok:
        return 3, None
    return 2, None


def render_progress_diagram(active_index: int, status_override):
    rows_html = []
    for i, (num, title, sub) in enumerate(PROGRESS_STEPS, start=1):
        if i < active_index:
            status = "done"
        elif i == active_index:
            status = status_override or "active"
        else:
            status = "pending"

        rows_html.append(
            f'''<div class="ss-prog-row">
                <div class="ss-prog-circle {status}">{num}</div>
                <div class="ss-prog-text">
                    <div class="ss-prog-title {status}">{title}</div>
                    <div class="ss-prog-sub">{sub}</div>
                </div>
            </div>'''
        )
        if i < len(PROGRESS_STEPS):
            connector_on = "on" if i < active_index else "off"
            rows_html.append(f'<div class="ss-prog-connector {connector_on}"></div>')

    return (
        '<div class="ss-progress">'
        + "".join(rows_html)
        + "</div>"
    )


